using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- CalculateTotal: DataRow for simple inline cases ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price with 8% tax")]
    [DataRow(0.00, 5, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    public void CalculateTotal_NegativeUnitPrice_Throws(double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    public void CalculateTotal_NegativeQuantity_Throws(double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below 0")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_Throws(double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // --- ApplyDiscount: DynamicData with ValueTuples for complex scenarios ---

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 0m, 100m),
        (100m, 10m, 90m),
        (100m, 50m, 50m),
        (100m, 100m, 0m),
        (200m, 25m, 150m),
        (49.99m, 20m, 39.992m),
        (0m, 50m, 0m),
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountData))]
    public void ApplyDiscount_InvalidDiscountPercent_Throws(decimal price, decimal discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    public static IEnumerable<(decimal price, decimal discountPercent)> InvalidDiscountData =>
    [
        (100m, -1m),
        (100m, 101m),
        (50m, -0.01m),
        (50m, 100.01m),
    ];
}

